import Link from "next/link";
import AdversarialPage from "../adversarial/page";
import ContradictionsPage from "../contradictions/page";
import DecayPage from "../decay/page";
import EvalPage from "../eval/page";
import FoundersPage from "../founders/page";
import MethodsPage from "../methods/page";
import OpenQuestionsPage from "../open-questions/page";
import PeerReviewPage from "../peer-review/[conclusionId]/page";
import PostMortemPage from "../post-mortem/page";
import ProvenancePage from "../provenance/page";
import ReviewQueuePage from "../q/review/page";
import RigorGatePage from "../rigor-gate/page";
import RigorGateDetailPage from "../rigor-gate/[submissionId]/page";
import ScoreboardPage from "../scoreboard/page";

type OpsSearchParams = {
  panel?: string;
  target?: string;
  ledger?: string;
  asOf?: string;
  showResolved?: string;
  author?: string;
  engage?: string;
};

const OPS_PANELS = [
  {
    id: "provenance",
    label: "Provenance",
    detail: "Extraction records and source chains.",
  },
  {
    id: "contradictions",
    label: "Contradictions",
    detail: "Claim pairs whose coherence layers disagree.",
  },
  {
    id: "peer-review",
    label: "Peer review",
    detail: "Per-conclusion review history, opened from a conclusion detail page.",
  },
  {
    id: "decay",
    label: "Decay",
    detail: "Confidence freshness and revalidation.",
  },
  {
    id: "rigor-gate",
    label: "Rigor gate",
    detail: "Mutation approvals, rejections, and overrides.",
  },
  {
    id: "methods",
    label: "Methods",
    detail: "Registered extraction and review methods.",
  },
] as const;

export default async function OpsPage({
  searchParams,
}: {
  searchParams: Promise<OpsSearchParams>;
}) {
  const sp = await searchParams;
  const panel = sp.panel || "overview";
  const target = firstPathSegment(sp.target);

  if (panel === "provenance") return <ProvenancePage />;
  if (panel === "eval") return <EvalPage />;
  if (panel === "contradictions") {
    return (
      <ContradictionsPage
        searchParams={Promise.resolve({
          asOf: sp.asOf,
          showResolved: sp.showResolved,
        })}
      />
    );
  }
  if (panel === "peer-review") {
    if (!target) return <PeerReviewIndex />;
    return (
      <PeerReviewPage
        params={Promise.resolve({ conclusionId: target })}
        searchParams={Promise.resolve({ ledger: sp.ledger })}
      />
    );
  }
  if (panel === "open-questions") return <OpenQuestionsPage />;
  if (panel === "adversarial") return <AdversarialPage />;
  if (panel === "layer-review") return <ReviewQueuePage />;
  if (panel === "calibration") {
    return (
      <ScoreboardPage
        searchParams={Promise.resolve({
          author: sp.author,
          engage: sp.engage,
        })}
      />
    );
  }
  if (panel === "post-mortem") return <PostMortemPage />;
  if (panel === "decay") {
    return <DecayPage searchParams={Promise.resolve({ ledger: sp.ledger })} />;
  }
  if (panel === "rigor-gate") {
    if (target) {
      return (
        <RigorGateDetailPage
          params={Promise.resolve({ submissionId: target })}
          searchParams={Promise.resolve({ ledger: sp.ledger })}
        />
      );
    }
    return <RigorGatePage searchParams={Promise.resolve({ ledger: sp.ledger })} />;
  }
  if (panel === "methods") return <MethodsPage />;
  if (panel === "founders") {
    return <FoundersPage searchParams={Promise.resolve({ asOf: sp.asOf })} />;
  }

  return <OpsOverview />;
}

function firstPathSegment(value: string | undefined): string {
  return (value || "").split("/").filter(Boolean)[0] || "";
}

function OpsOverview() {
  return (
    <main style={{ maxWidth: "1040px", margin: "0 auto", padding: "3rem 2rem" }}>
      <header style={{ marginBottom: "1.75rem" }}>
        <h1
          style={{
            fontFamily: "'Cinzel Decorative', 'Cinzel', serif",
            fontSize: "1.8rem",
            letterSpacing: "0.16em",
            color: "var(--amber)",
            margin: 0,
            textShadow: "var(--glow-sm)",
          }}
        >
          Ops
        </h1>
        <p
          className="mono"
          style={{
            color: "var(--amber-dim)",
            fontSize: "0.62rem",
            letterSpacing: "0.24em",
            textTransform: "uppercase",
          }}
        >
          Advanced tooling · Audit surfaces · Founder operations
        </p>
      </header>

      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(220px, 1fr))", gap: "0.85rem" }}>
        {OPS_PANELS.map((panel) => (
          <Link
            key={panel.id}
            href={`/ops?panel=${panel.id}`}
            className="portal-card"
            style={{
              color: "inherit",
              display: "block",
              padding: "1rem 1.1rem",
              textDecoration: "none",
            }}
          >
            <h2
              style={{
                color: "var(--gold)",
                fontFamily: "'Cinzel', serif",
                fontSize: "0.9rem",
                letterSpacing: "0.1em",
                margin: 0,
              }}
            >
              {panel.label}
            </h2>
            <p style={{ color: "var(--parchment-dim)", fontSize: "0.85rem", lineHeight: 1.5, margin: "0.5rem 0 0" }}>
              {panel.detail}
            </p>
          </Link>
        ))}
      </div>
    </main>
  );
}

function PeerReviewIndex() {
  return (
    <main style={{ maxWidth: "840px", margin: "0 auto", padding: "3rem 2rem" }}>
      <h1
        style={{
          fontFamily: "'Cinzel', serif",
          color: "var(--gold)",
          letterSpacing: "0.08em",
        }}
      >
        Peer review
      </h1>
      <div className="portal-card" style={{ padding: "1rem 1.25rem", color: "var(--parchment-dim)", lineHeight: 1.6 }}>
        Peer review is now opened from an individual conclusion. Go to{" "}
        <Link href="/knowledge?tab=conclusions" style={{ color: "var(--gold)" }}>
          Knowledge
        </Link>
        , choose a conclusion, then use its peer review tab or action bar.
      </div>
    </main>
  );
}

generator client {
  provider = "prisma-client-js"
  // No custom `output` — Prisma 7 puts types alongside the runtime at
  // `node_modules/.prisma/client` automatically when you leave this blank,
  // and `@prisma/client` re-exports them. Explicitly setting
  // `output = "../node_modules/.prisma/client"` used to work on Prisma 6
  // but in Prisma 7 it only emits the WASM runtime (no .d.ts files),
  // which breaks every `import { PrismaClient } from "@prisma/client"`.
}

// Postgres everywhere (Supabase / Neon / local Docker Postgres). Prisma bakes
// the provider into the generated migrations, so you can't switch to SQLite
// per-env with the same migration history. Use a local Postgres container
// (see `docker-compose.dev.yml`) for offline dev, or point DATABASE_URL at
// your Supabase project for both dev and prod.
datasource db {
  provider = "postgresql"
}

enum CurrentEventStatus {
  OBSERVED
  ENRICHED
  OPINED
  ABSTAINED
  REVOKED
}

enum CurrentEventSource {
  X_TWITTER
  RSS
  MANUAL
}

enum OpinionStance {
  AGREES
  DISAGREES
  COMPLICATES
  ABSTAINED
}

enum AbstentionReason {
  INSUFFICIENT_SOURCES
  ABSTAIN_OFF_DOMAIN
  NEAR_DUPLICATE
  BUDGET
  CITATION_FABRICATION
  REVOKED_SOURCES
}

enum FollowUpRole {
  USER
  ASSISTANT
}

enum ForecastSource {
  POLYMARKET
  KALSHI
}

enum ForecastMarketStatus {
  OPEN
  CLOSED
  RESOLVED
  CANCELLED
}

enum ForecastPredictionStatus {
  PUBLISHED
  ABSTAINED_INSUFFICIENT_SOURCES
  ABSTAINED_MARKET_EXPIRED
  ABSTAINED_NEAR_DUPLICATE
  ABSTAINED_BUDGET
  ABSTAINED_CITATION_FABRICATION
  ABSTAINED_REVOKED_SOURCES
}

enum ForecastSupportLabel {
  DIRECT
  INDIRECT
  CONTRARY
}

enum ForecastOutcome {
  YES
  NO
  CANCELLED
  AMBIGUOUS
}

enum ForecastBetMode {
  PAPER
  LIVE
}

enum ForecastExchange {
  POLYMARKET
  KALSHI
}

enum ForecastBetSide {

from __future__ import annotations

import contextvars
import hashlib
import json
import logging
import os
import subprocess
from datetime import datetime, timezone
from functools import wraps
from typing import Any, Callable
from uuid import uuid4

from pydantic import BaseModel

from noosphere.models import (
    CascadeEdgeRelation,
    Method,
    MethodImplRef,
    MethodInvocation,
    MethodType,
)
from noosphere.methods._hooks import _FAILURE_HOOKS, _POST_HOOKS, _PRE_HOOKS
from noosphere.methods._registry import REGISTRY
from noosphere.methods.composition import validate_depends_on
from noosphere.methods.domain_bounds import DomainBound, load_domain_bound

logger = logging.getLogger(__name__)

CORRELATION_ID: contextvars.ContextVar[str] = contextvars.ContextVar(
    "CORRELATION_ID", default=""
)
TENANT_ID: contextvars.ContextVar[str] = contextvars.ContextVar(
    "TENANT_ID", default="default"
)

_store_factory: Callable[..., Any] | None = None


def set_store_factory(factory: Callable[..., Any]) -> None:
    global _store_factory
    _store_factory = factory


def _get_store() -> Any:
    if _store_factory is not None:
        try:
            return _store_factory()
        except Exception:
            return None
    return None


def _canonical_json(obj: Any) -> str:
    if isinstance(obj, BaseModel):
        obj = obj.model_dump(mode="json")
    return json.dumps(obj, sort_keys=True, separators=(",", ":"), default=str)


def _current_git_sha() -> str:
    sha = os.environ.get("THESEUS_GIT_SHA")
    if sha:
        return sha
    try:
        result = subprocess.run(
            ["git", "rev-parse", "HEAD"],
            capture_output=True,
            text=True,
            timeout=5,
        )
        if result.returncode == 0:
            return result.stdout.strip()
    except Exception:
        pass
    return "unknown"


def _current_correlation_id() -> str:
    return CORRELATION_ID.get()


def _current_tenant_id() -> str:
    return TENANT_ID.get()


def _validate_against_schema(schema: Any, data: Any) -> Any:
    if isinstance(schema, type) and issubclass(schema, BaseModel):
        if isinstance(data, schema):
            return data
        return schema.model_validate(data)
    if isinstance(schema, dict) and schema:
        try:
            import jsonschema as _js

            _js.validate(data, schema)
        except ImportError:
            pass
    return data


def _utcnow() -> datetime:
    return datetime.now(timezone.utc)


def _run_failure_path(
    spec: Method,
    inv: MethodInvocation,
    validated_input: Any,
    exc: BaseException,
) -> None:
    inv = inv.model_copy(
        update={
            "ended_at": _utcnow(),
            "succeeded": False,
            "error_kind": type(exc).__name__,
        }
    )
    for hook_name, hook in _FAILURE_HOOKS:
        try:
            hook(spec, inv, validated_input, exc)
        except Exception:
            logger.exception("Failure hook %s raised", hook_name)
    store = _get_store()
    if store is not None:
        try:
            store.insert_method_invocation(inv)
        except Exception:
            logger.exception("Failed to persist invocation")


def register_method(
    *,
    name: str,
    version: str,
    method_type: MethodType,
    input_schema: Any,
    output_schema: Any,
    description: str,
    rationale: str,
    preconditions: list[str] | tuple[str, ...] = (),
    postconditions: list[str] | tuple[str, ...] = (),
    dependencies: list[tuple[str, str]] | tuple[tuple[str, str], ...] = (),
    depends_on: list[str] | tuple[str, ...] = (),
    owner: str,
    status: str = "active",
    nondeterministic: bool = False,
    emits_edges: list[CascadeEdgeRelation] | tuple[CascadeEdgeRelation, ...] = (),
    domain: Any = None,
) -> Callable:
    def decorator(fn: Callable) -> Callable:
        if isinstance(input_schema, type) and issubclass(input_schema, BaseModel):
            in_schema_dict = input_schema.model_json_schema()
        elif isinstance(input_schema, dict):
            in_schema_dict = input_schema
        else:
            in_schema_dict = {}

        if isinstance(output_schema, type) and issubclass(output_schema, BaseModel):
            out_schema_dict = output_schema.model_json_schema()
        elif isinstance(output_schema, dict):
            out_schema_dict = output_schema
        else:
            out_schema_dict = {}

        impl = MethodImplRef(
            module=fn.__module__,
            fn_name=fn.__qualname__,
            git_sha=_current_git_sha(),
            image_digest=None,
        )

        spec_for_hash = {
            "name": name,
            "version": version,
            "method_type": method_type.value,
            "input_schema": in_schema_dict,
            "output_schema": out_schema_dict,
            "description": description,
            "rationale": rationale,
            "preconditions": list(preconditions),
            "postconditions": list(postconditions),
            "dependencies": [list(d) for d in dependencies],
            "implementation": impl.model_dump(mode="json"),
            "owner": owner,
            "status": status,
            "nondeterministic": nondeterministic,
        }

        method_id = hashlib.sha256(
            _canonical_json(spec_for_hash).encode()
        ).hexdigest()[:32]

        spec = Method(
            method_id=method_id,
            name=name,
            version=version,
            method_type=method_type,
            input_schema=in_schema_dict,
            output_schema=out_schema_dict,
            description=description,
            rationale=rationale,
            preconditions=list(preconditions),
            postconditions=list(postconditions),
            dependencies=list(dependencies),
            implementation=impl,
            owner=owner,
            status=status,
            nondeterministic=nondeterministic,
            created_at=_utcnow(),
        )

        @wraps(fn)
        def wrapped(input_data: Any) -> Any:
            validated_input = _validate_against_schema(input_schema, input_data)
            input_hash = hashlib.sha256(
                _canonical_json(validated_input).encode()
            ).hexdigest()

            inv = MethodInvocation(
                id=str(uuid4()),
                method_id=spec.method_id,
                input_hash=input_hash,
                output_hash="",
                started_at=_utcnow(),
                ended_at=None,
                succeeded=False,
                error_kind=None,
                correlation_id=_current_correlation_id(),
                tenant_id=_current_tenant_id(),
            )

            try:
                for _hook_name, hook in _PRE_HOOKS:
                    hook(spec, inv, validated_input)
            except Exception as e:
                _run_failure_path(spec, inv, validated_input, e)
                raise

            try:
                result = fn(validated_input)
                _validate_against_schema(output_schema, result)
                output_hash = hashlib.sha256(
                    _canonical_json(result).encode()
                ).hexdigest()
                inv = inv.model_copy(
                    update={
                        "ended_at": _utcnow(),
                        "succeeded": True,
                        "output_hash": output_hash,
                    }
                )

                for hook_name, hook in _POST_HOOKS:
                    try:
                        hook(spec, inv, validated_input, result)
                    except Exception:
                        logger.exception("Post-hook %s raised", hook_name)

                store = _get_store()
                if store is not None:
                    try:
                        store.insert_method_invocation(inv)
                    except Exception:
                        logger.exception("Failed to persist invocation")

                return result
            except Exception as e:
                _run_failure_path(spec, inv, validated_input, e)
                raise

        wrapped.__method_spec__ = spec  # type: ignore[attr-defined]

        REGISTRY.register(spec, wrapped)

        # Composition DAG: declared depends_on names must already be
        # registered. Decoration-time check so a typo fails CI rather
        # than silently leaving a ghost edge in the graph.
        if depends_on:
            validate_depends_on(
                REGISTRY.known_method_names(), name, list(depends_on)
            )
            REGISTRY.set_depends_on(name, list(depends_on))
        else:
            # Always seed the side table so build_dag() sees this node.
            REGISTRY.set_depends_on(name, [])

        if emits_edges:
            REGISTRY.set_emits_edges(method_id, list(emits_edges))

        # Domain bound is optional; when present it is normalized via the
        # deterministic loader so a bare list[str] of tags or a dict-style
        # declaration both produce the same DomainBound shape.
        if domain is not None:
            bound: DomainBound = (
                domain if isinstance(domain, DomainBound) else load_domain_bound(domain)
            )
            REGISTRY.set_domain_bound(name, bound)

